                            Id = 9,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Repository Pattern\n\n> 💡 **Analogia**: Pense em uma biblioteca. Você pede ao bibliotecário um livro pelo título — você não sabe se ele está na prateleira A, no depósito ou digitalizado. O bibliotecário (*repository*) sabe onde buscar. Você (*controller/service*) só se importa em receber o livro — os detalhes de onde está armazenado não são problema seu.\n\nO Repository Pattern isola a **lógica de acesso a dados** da lógica de negócio. Controllers e Services não sabem se os dados vêm de SQLite, SQL Server, uma API ou memória.\n\n### O problema sem Repository\n\n```csharp\n// SEM REPOSITORY — controller acoplado ao banco\npublic class PedidoController : ControllerBase\n{\n    private readonly AppDbContext _ctx;\n\n    [HttpGet(\"{id}\")]\n    public async Task<IActionResult> Get(int id)\n    {\n        var pedido = await _ctx.Pedidos.FindAsync(id); // acoplamento direto ao EF\n        return Ok(pedido);\n    }\n    // Problema: para testar, precisa de um banco real\n}\n```\n\n### A solução: Interface + Implementação\n\n```csharp\n// 1. Interface — define o CONTRATO (o que o repositório faz)\npublic interface IProdutoRepository\n{\n    Task<Produto?>           ObterPorIdAsync(int id);\n    Task<IEnumerable<Produto>> ObterTodosAsync();\n    Task<IEnumerable<Produto>> ObterPorCategoriaAsync(string categoria);\n    Task                      AdicionarAsync(Produto produto);\n    void                      Atualizar(Produto produto);\n    void                      Remover(Produto produto);\n    Task<bool>                SalvarAsync();\n}\n\n// 2. Implementação — DETALHE de infraestrutura (EF Core)\npublic class ProdutoRepository(AppDbContext ctx) : IProdutoRepository\n{\n    public async Task<Produto?> ObterPorIdAsync(int id)\n        => await ctx.Produtos.FindAsync(id);\n\n    public async Task<IEnumerable<Produto>> ObterTodosAsync()\n        => await ctx.Produtos.AsNoTracking().ToListAsync(); // AsNoTracking = mais rápido para leitura\n\n    public async Task AdicionarAsync(Produto produto)\n        => await ctx.Produtos.AddAsync(produto);\n\n    public void Atualizar(Produto produto)\n        => ctx.Produtos.Update(produto);\n\n    public async Task<bool> SalvarAsync()\n        => await ctx.SaveChangesAsync() > 0;\n}\n\n// 3. Controller — depende da INTERFACE, nunca da implementação\npublic class ProdutoController(IProdutoRepository repo) : ControllerBase\n{\n    [HttpGet(\"{id}\")]\n    public async Task<IActionResult> Get(int id)\n    {\n        var produto = await repo.ObterPorIdAsync(id);\n        return produto is null ? NotFound() : Ok(produto);\n    }\n}\n```\n\n### Registro no DI (Dependency Injection)\n\n```csharp\n// Program.cs\nbuilder.Services.AddScoped<IProdutoRepository, ProdutoRepository>();\n// AddScoped = uma instância por requisição HTTP (ideal para DbContext)\n```\n\n### Testabilidade — o grande benefício\n\n```csharp\n// Em testes, substitua com um fake sem banco real\npublic class FakeProdutoRepository : IProdutoRepository\n{\n    private readonly List<Produto> _dados = new();\n\n    public Task<Produto?> ObterPorIdAsync(int id)\n        => Task.FromResult(_dados.FirstOrDefault(p => p.Id == id));\n\n    public Task AdicionarAsync(Produto p) { _dados.Add(p); return Task.CompletedTask; }\n    public Task<bool> SalvarAsync() => Task.FromResult(true);\n    // ...\n}\n\n// O Controller funciona sem nenhuma mudança — recebe a interface, não sabe qual implementação é\n```\n\n> **Princípio**: Controllers dependem de **abstrações** (interfaces), não de **detalhes** (EF Core, SQL). Isso é o **D** do SOLID — Dependency Inversion Principle.",
