                        {
                            Id = 26,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Implementando JWT no ASP.NET Core\n\n### Instalação\n\n```bash\ndotnet add package Microsoft.AspNetCore.Authentication.JwtBearer\n```\n\n### Gerando o token\n\n```csharp\npublic string GerarToken(Usuario usuario)\n{\n    var chave = new SymmetricSecurityKey(\n        Encoding.UTF8.GetBytes(\"sua-chave-secreta-minimo-32-chars\"));\n    var credenciais = new SigningCredentials(chave, SecurityAlgorithms.HmacSha256);\n\n    var claims = new[]\n    {\n        new Claim(ClaimTypes.NameIdentifier, usuario.Id.ToString()),\n        new Claim(ClaimTypes.Name, usuario.Nome)\n    };\n\n    var token = new JwtSecurityToken(\n        issuer: \"minha-api\",\n        audience: \"meu-app\",\n        claims: claims,\n        expires: DateTime.UtcNow.AddHours(8),\n        signingCredentials: credenciais);\n\n    return new JwtSecurityTokenHandler().WriteToken(token);\n}\n```\n\n### Configurando no Program.cs\n\n```csharp\nbuilder.Services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme)\n    .AddJwtBearer(opt =>\n    {\n        opt.TokenValidationParameters = new()\n        {\n            ValidateIssuerSigningKey = true,\n            IssuerSigningKey = new SymmetricSecurityKey(\n                Encoding.UTF8.GetBytes(config[\"Jwt:Key\"]!)),\n            ValidateIssuer = false,\n            ValidateAudience = false\n        };\n    });\n\napp.UseAuthentication();\napp.UseAuthorization();\n```",
                            Descricao = "Gerando tokens, configurando autenticação e protegendo endpoints",
                            ModuloId = 9,
