                            Id = 31,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Testes Unitários com xUnit\n\nTestes unitários verificam uma **unidade isolada** de código (método ou classe) sem dependências externas.\n\n### Setup\n\n```bash\ndotnet new xunit -n MeuProjeto.Tests\ndotnet add reference ../MeuProjeto/MeuProjeto.csproj\n```\n\n### Estrutura AAA\n\n```csharp\npublic class CalculadoraTests\n{\n    [Fact]  // marca como teste\n    public void Somar_DoisNumeros_RetornaSoma()\n    {\n        // Arrange — prepara o cenário\n        var calc = new Calculadora();\n\n        // Act — executa a ação\n        var resultado = calc.Somar(2, 3);\n\n        // Assert — verifica o resultado\n        Assert.Equal(5, resultado);\n    }\n\n    [Theory]  // teste parametrizado\n    [InlineData(2, 3, 5)]\n    [InlineData(-1, 1, 0)]\n    [InlineData(0, 0, 0)]\n    public void Somar_Parametrizado(int a, int b, int esperado)\n    {\n        var calc = new Calculadora();\n        Assert.Equal(esperado, calc.Somar(a, b));\n    }\n}\n```\n\n> **[Fact]** = um teste único. **[Theory]** + **[InlineData]** = mesmo teste com múltiplos inputs.",
                            Descricao = "O que testar, estrutura Arrange-Act-Assert e escrevendo testes com xUnit",
                            ModuloId = 11,
                            Ordem = 1,
                            Titulo = "Fundamentos de Testes Unitários",
                            XPRecompensa = 18
                        },
                        new
                        {
                            Id = 32,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Mocking com Moq\n\nMocks substituem dependências reais (banco, email, API externa) por objetos controlados.\n\n```bash\ndotnet add package Moq\n```\n\n### Exemplo — testando um service\n\n```csharp\npublic class ProdutoServiceTests\n{\n    [Fact]\n    public async Task ObterPorId_ProdutoExistente_RetornaProduto()\n    {\n        // Arrange\n        var mockRepo = new Mock<IProdutoRepository>();\n        mockRepo.Setup(r => r.ObterPorIdAsync(1))\n                .ReturnsAsync(new Produto { Id = 1, Nome = \"Teclado\" });\n\n        var service = new ProdutoService(mockRepo.Object);\n\n        // Act\n        var produto = await service.ObterPorIdAsync(1);\n\n        // Assert\n        Assert.NotNull(produto);\n        Assert.Equal(\"Teclado\", produto.Nome);\n        mockRepo.Verify(r => r.ObterPorIdAsync(1), Times.Once);\n    }\n}\n```\n\n### Operações principais do Moq\n\n```csharp\nmock.Setup(x => x.Metodo()).Returns(valor);         // configura retorno\nmock.Setup(x => x.MetodoAsync()).ReturnsAsync(valor); // async\nmock.Verify(x => x.Metodo(), Times.Once());           // verifica chamada\nmock.Verify(x => x.Metodo(), Times.Never());          // verifica que NÃO foi chamado\n```",
                            Descricao = "Isolando dependências com mocks para testar unidades em isolamento",
                            ModuloId = 11,
                            Ordem = 2,
                            Titulo = "Mocking com Moq",
                            XPRecompensa = 18
                        },
                        new
                        {
                            Id = 33,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## TDD — Test-Driven Development\n\nTDD inverte o fluxo: você escreve o **teste primeiro**, depois o código para fazê-lo passar.\n\n### Ciclo Red-Green-Refactor\n\n```\n🔴 RED    → Escreva um teste que falha (o código ainda não existe)\n🟢 GREEN  → Escreva o mínimo de código para o teste passar\n🔵 REFACTOR → Melhore o código sem quebrar o teste\n```\n\n### Exemplo prático\n\n```csharp\n// 🔴 RED — escrevo o teste primeiro\n[Fact]\npublic void Desconto_PedidoAcima100_Aplica10Porcento()\n{\n    var pedido = new Pedido { Total = 200m };\n    pedido.AplicarDesconto();\n    Assert.Equal(180m, pedido.Total);\n}\n\n// 🟢 GREEN — mínimo para passar\npublic void AplicarDesconto()\n{\n    if (Total >= 100) Total *= 0.9m;\n}\n\n// 🔵 REFACTOR — melhoro o design\npublic void AplicarDesconto()\n{\n    const decimal LimiteDesconto = 100m;\n    const decimal PercentualDesconto = 0.10m;\n    if (Total >= LimiteDesconto)\n        Total -= Total * PercentualDesconto;\n}\n```\n\n> **Benefício principal**: TDD força você a pensar na **interface** antes da implementação, resultando em código mais modular e testável.",
                            Descricao = "O ciclo Red-Green-Refactor e como o TDD guia o design do código",
                            ModuloId = 11,
                            Ordem = 3,
                            Titulo = "Test-Driven Development",
                            XPRecompensa = 18
                        },
                        new
                        {
                            Id = 34,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Injeção de Dependência\n\n**Injeção de Dependência (DI)** é um padrão onde um objeto recebe suas dependências de fora, em vez de criá-las internamente. Isso implementa o princípio **Dependency Inversion (D do SOLID)**.\n\n### Sem DI — fortemente acoplado\n\n```csharp\npublic class PedidoService\n{\n    private readonly EmailService _email = new EmailService(); // acoplamento!\n    private readonly SqlRepository _repo = new SqlRepository(\"connection...\");\n\n    public void Processar(Pedido p)\n    {\n        _repo.Salvar(p);\n        _email.Enviar(p.Email, \"Pedido confirmado\");\n    }\n    // impossível testar sem banco e servidor de email reais\n}\n```\n\n### Com DI — desacoplado\n\n```csharp\npublic class PedidoService\n{\n    private readonly IPedidoRepository _repo;\n    private readonly IEmailService _email;\n\n    public PedidoService(IPedidoRepository repo, IEmailService email)\n    {\n        _repo = repo;   // recebe de fora\n        _email = email; // recebe de fora\n    }\n\n    public void Processar(Pedido p)\n    {\n        _repo.Salvar(p);\n        _email.Enviar(p.Email, \"Pedido confirmado\");\n    }\n    // testável: basta passar mocks no construtor\n}\n```\n\n> **IoC (Inversion of Control)**: em vez de a classe controlar suas dependências, o **contêiner** injeta o que ela precisa.",
                            Descricao = "O que é injeção de dependência, inversão de controle e por que usar",
                            ModuloId = 12,
                            Ordem = 1,
                            Titulo = "Princípios de DI",
                            XPRecompensa = 18
                        },
                        new
                        {
                            Id = 35,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## IoC Container do ASP.NET Core\n\nO .NET tem um contêiner de DI built-in via `IServiceCollection`. Você registra serviços no `Program.cs` e o framework injeta automaticamente onde necessário.\n\n### Registrando serviços\n\n```csharp\n// Interfaces → implementações\nbuilder.Services.AddScoped<IProdutoRepository, ProdutoRepository>();\nbuilder.Services.AddScoped<IEmailService, SmtpEmailService>();\nbuilder.Services.AddSingleton<ICacheService, MemoryCacheService>();\nbuilder.Services.AddTransient<IValidationService, ValidationService>();\n\n// Classe concreta (sem interface)\nbuilder.Services.AddScoped<ReportGenerator>();\n```\n\n### Resolvendo fora do construtor\n\n```csharp\n// Em casos especiais, resolução manual\nusing var scope = app.Services.CreateScope();\nvar repo = scope.ServiceProvider.GetRequiredService<IProdutoRepository>();\n```\n\n### Injeção em controllers\n\n```csharp\npublic class ProdutosController : ControllerBase\n{\n    public ProdutosController(\n        IProdutoRepository repo,    // injetado automaticamente\n        ILogger<ProdutosController> logger)  // também injetado\n    { ... }\n}\n```\n\n> O contêiner resolve recursivamente: se `ProdutoRepository` depende de `AppDbContext`, o contêiner injeta o `DbContext` também.",
                            Descricao = "Registrando serviços no IServiceCollection e resolvendo dependências",
                            ModuloId = 12,
                            Ordem = 2,
                            Titulo = "IoC Container no .NET",
                            XPRecompensa = 18
                        },
                        new
                        {
                            Id = 36,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Lifetimes de Serviços\n\nO lifetime define **por quanto tempo** uma instância do serviço é reutilizada.\n\n### Os três lifetimes\n\n| Lifetime | Instância criada | Quando usar |\n|---|---|---|\n| **Transient** | A cada injeção | Serviços leves, stateless |\n| **Scoped** | Uma por requisição HTTP | DbContext, repositórios |\n| **Singleton** | Uma para toda a app | Cache, configuração, logger |\n\n### Exemplos\n\n```csharp\n// Transient — nova instância toda vez\nbuilder.Services.AddTransient<IEmailValidator, EmailValidator>();\n\n// Scoped — mesma instância durante a requisição\nbuilder.Services.AddScoped<AppDbContext>();  // EF Core requer Scoped\nbuilder.Services.AddScoped<IProdutoRepository, ProdutoRepository>();\n\n// Singleton — mesma instância para sempre\nbuilder.Services.AddSingleton<IConfiguration>(builder.Configuration);\nbuilder.Services.AddSingleton<ICacheService, InMemoryCacheService>();\n```\n\n### ⚠️ Captive Dependency\n\n```csharp\n// ERRO: Singleton capturando um Scoped\n// O Scoped vive mais do que deveria!\npublic class MeuSingleton\n{\n    public MeuSingleton(AppDbContext ctx) { }  // DbContext é Scoped!\n}\n// O .NET lança exceção se ValidateScopes = true\n```\n\n> Regra: **Singleton** nunca deve depender de **Scoped** ou **Transient**. Um serviço de vida longa não pode capturar um de vida curta.",
                            Descricao = "Entendendo os ciclos de vida dos serviços e quando usar cada um",
                            ModuloId = 12,
                            Ordem = 3,
                            Titulo = "Lifetimes: Transient, Scoped, Singleton",
                            XPRecompensa = 18
                        },
                        new
                        {
                            Id = 37,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Clean Architecture\n\nProposta por Robert C. Martin (Uncle Bob), a Clean Architecture organiza o código em **camadas concêntricas**, onde as dependências sempre apontam para dentro — do código de infraestrutura para o núcleo de domínio.\n\n### Os círculos (de dentro para fora)\n\n```\n┌─────────────────────────────────────────┐\n│  Infrastructure (EF, HTTP, Email)       │\n│  ┌───────────────────────────────────┐  │\n│  │  Interface Adapters (Controllers) │  │\n│  │  ┌─────────────────────────────┐  │  │\n│  │  │  Application (Use Cases)    │  │  │\n│  │  │  ┌───────────────────────┐  │  │  │\n│  │  │  │  Domain (Entities)    │  │  │  │\n│  │  │  └───────────────────────┘  │  │  │\n│  │  └─────────────────────────────┘  │  │\n│  └───────────────────────────────────┘  │\n└─────────────────────────────────────────┘\n```\n\n### A Regra da Dependência\n\n> *Dependências de código-fonte só podem apontar para dentro.*\n\n- **Domain**: entidades e regras de negócio puras — **zero dependências externas**\n- **Application**: casos de uso, orquestra o domínio — depende só do Domain\n- **Infrastructure**: EF Core, HTTP, email — implementa interfaces do Domain/Application\n- **Presentation**: controllers, CLI, gRPC — depende da Application\n\n> O Domain não conhece EF Core, ASP.NET ou qualquer framework. Ele é **puro C#** e pode ser testado sem infraestrutura.",
                            Descricao = "Por que separar em camadas, a Regra da Dependência e os círculos da Clean Architecture",
                            ModuloId = 13,
                            Ordem = 1,
                            Titulo = "Separação de Camadas",
                            XPRecompensa = 25
                        },
                        new
                        {
                            Id = 38,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Entities, Use Cases e Interfaces\n\n### Entities (Domain Layer)\n\n```csharp\n// Domínio puro — sem atributos de EF, sem DTOs\npublic class Pedido\n{\n    public int Id { get; private set; }\n    public decimal Total { get; private set; }\n    public StatusPedido Status { get; private set; }\n\n    public void Confirmar()\n    {\n        if (Status != StatusPedido.Pendente)\n            throw new DomainException(\"Apenas pedidos pendentes podem ser confirmados\");\n        Status = StatusPedido.Confirmado;\n    }\n}\n```\n\n### Use Cases (Application Layer)\n\n```csharp\n// Um Use Case = uma ação do sistema\npublic class ConfirmarPedidoUseCase\n{\n    private readonly IPedidoRepository _repo;  // interface do Domain\n    private readonly IEmailService _email;     // interface do Domain\n\n    public ConfirmarPedidoUseCase(\n        IPedidoRepository repo, IEmailService email)\n    { _repo = repo; _email = email; }\n\n    public async Task ExecutarAsync(int pedidoId)\n    {\n        var pedido = await _repo.ObterPorIdAsync(pedidoId)\n            ?? throw new NotFoundException(\"Pedido não encontrado\");\n\n        pedido.Confirmar();  // lógica no domínio\n        await _repo.SalvarAsync();\n        await _email.EnviarConfirmacaoAsync(pedido);\n    }\n}\n```\n\n### Dependency Inversion aplicado\n\n```csharp\n// Domain define a interface\npublic interface IPedidoRepository\n{\n    Task<Pedido?> ObterPorIdAsync(int id);\n    Task SalvarAsync();\n}\n\n// Infrastructure implementa\npublic class EfPedidoRepository : IPedidoRepository\n{\n    // usa EF Core — Domain não sabe disso\n}\n```",
                            Descricao = "Modelando o domínio, definindo Use Cases e usando o Dependency Inversion",
                            ModuloId = 13,
                            Ordem = 2,
                            Titulo = "Entities, Use Cases e Interfaces",
                            XPRecompensa = 25
                        },
                        new
                        {
                            Id = 39,
                            Ativo = true,
                            ConteudoTeoricoMarkdown = "## Aplicando Clean Architecture em uma API .NET\n\n### Estrutura de projetos (solution)\n\n```\nMeuApp.sln\n├── MeuApp.Domain/           → Entities, Interfaces, Domain Exceptions\n├── MeuApp.Application/      → Use Cases, DTOs, Validators\n├── MeuApp.Infrastructure/   → EF Core, Repositórios, Serviços externos\n└── MeuApp.API/              → Controllers, Program.cs, Middleware\n```\n\n**Referências entre projetos:**\n```\nAPI → Application → Domain\nInfrastructure → Domain  (implementa interfaces)\nAPI → Infrastructure     (apenas para registrar DI)\n```\n\n### Program.cs — montando tudo\n\n```csharp\n// API sabe de tudo (apenas para registrar)\nbuilder.Services.AddScoped<IPedidoRepository, EfPedidoRepository>();\nbuilder.Services.AddScoped<IEmailService, SmtpEmailService>();\nbuilder.Services.AddScoped<ConfirmarPedidoUseCase>();\n```\n\n### Controller delegando para Use Case\n\n```csharp\n[HttpPost(\"{id}/confirmar\")]\npublic async Task<IActionResult> Confirmar(\n    int id,\n    [FromServices] ConfirmarPedidoUseCase useCase)\n{\n    await useCase.ExecutarAsync(id);\n    return NoContent();\n}\n// Controller tem zero lógica de negócio\n```\n\n> **Clean Architecture vs camadas tradicionais**: a diferença chave é que as interfaces ficam no **Domain** (centro), não na Infrastructure. Isso inverte a dependência e protege o núcleo do negócio.",
                            Descricao = "Estrutura de projetos, organização de pastas e montando a aplicação",
                            ModuloId = 13,
                            Ordem = 3,
                            Titulo = "Clean Architecture em APIs .NET",
                            XPRecompensa = 25
                        });
                });

